// pages/base.page.ts
import { Page } from '@playwright/test';

export class BasePage {
  constructor(protected page: Page) {}

  async click(selector: string) {
    await this.page.click(selector);
  }

  async fill(selector: string, value: string) {
    await this.page.fill(selector, value);
  }
}


login.page.ts
import { Page } from '@playwright/test';
import { BasePage } from './base.page';

export class LoginPage extends BasePage {
  constructor(page: Page) {
    super(page);
  }

  async login(username: string, password: string) {
    await this.fill('#username', username);
    await this.fill('#password', password);
    await this.click('#login-btn');
  }
}

alert.page.ts
import { Page, expect } from '@playwright/test';
import { BasePage } from './base.page';

export class AlertPage extends BasePage {
  constructor(page: Page) {
    super(page);
  }

  async sendAlert(message: string) {
    await this.fill('#message-box', message);
    await this.click('#send-alert-btn');
  }

  async verifyAlertDelivered() {
    await expect(this.page.locator('#status')).toHaveText('Delivered');
  }
}


// tests/alert.spec.ts
import { test } from '@playwright/test';
import { LoginPage } from '../pages/login.page';
import { AlertPage } from '../pages/alert.page';

test('Send alert successfully', async ({ page }) => {
  const loginPage = new LoginPage(page);
  const alertPage = new AlertPage(page);

  await page.goto('https://app-url');

  await loginPage.login('user', 'pass');
  await alertPage.sendAlert('Emergency Alert');
  await alertPage.verifyAlertDelivered();
});

// full-ui-actions.spec.ts

import { test, expect } from '@playwright/test';

test('Full UI actions demo', async ({ page }) => {

  // 1. Navigate to URL
  await page.goto('https://example.com');

  // 2. Fill input fields
  await page.fill('#username', 'testuser');
  await page.fill('#password', 'password123');

  // 3. Click button
  await page.click('#login-btn');

  // 4. Wait for element
  await page.waitForSelector('#dashboard');

  // 5. Verify element visible
  await expect(page.locator('#dashboard')).toBeVisible();

  // 6. Get text and print
  const text = await page.textContent('#welcome-msg');
  console.log('Text:', text);

  // 7. Select dropdown
  await page.selectOption('#country', 'India');

  // 8. Handle checkbox
  await page.check('#accept-terms');

  // 9. Handle radio button
  await page.check('#male');

  // 10. Upload file
  await page.setInputFiles('#file-upload', 'tests/sample.pdf');

  // 11. Scroll page
  await page.mouse.wheel(0, 500);

  // 12. Hover action
  await page.hover('#menu');

  // 13. Click from hover dropdown
  await page.click('#submenu-item');

  // 14. Wait for API response (important)
  await page.waitForResponse(resp =>
    resp.url().includes('/api/data') && resp.status() === 200
  );

  // 15. Handle alert popup
  page.on('dialog', async dialog => {
    console.log(dialog.message());
    await dialog.accept();
  });

  await page.click('#delete-btn');

  // 16. Navigate back
  await page.goBack();

  // 17. Refresh page
  await page.reload();

  // 18. Assertion with text
  await expect(page.locator('#status')).toHaveText('Success');

});
